<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';use App\Repositories\ControlEscaneres\Pdo\{PdoScannerRepository,PdoScannerMovementRepository,PdoScannerInspectionRepository,PdoScannerIncidentRepository,PdoEvidenceRepository,PdoAuditRepository,PdoAuditQueryRepository,PdoScannerDashboardQuery,PdoScannerHistoryQuery};use App\Repositories\ControlEscaneres\TransactionManager;use App\DTO\ControlEscaneres\{ScannerCreateData,AuthenticatedActorData,ScannerMovementCreateData,ScannerInspectionCreateData,ScannerInspectionDetailData,ScannerIncidentCreateData,ScannerEvidenceMetadata,AuditEventData};use App\Domain\ControlEscaneres\{ScannerCode,ScannerStatus,ScannerFolio,InspectionType,IncidentSeverity,BatteryPercentage};
$pdo=new PDO('sqlite::memory:');$pdo->exec(file_get_contents(__DIR__.'/fixtures/sqlite-schema.sql'));$actor=new AuthenticatedActorData(7,'session','127.0.0.1');$sc=new PdoScannerRepository($pdo);$scanner=$sc->create(new ScannerCreateData(new ScannerCode('SC-0001'),'QR1','Zebra','TC22',new ScannerStatus('disponible')),7);$mv=new PdoScannerMovementRepository($pdo);$movement=$mv->create(new ScannerMovementCreateData($scanner->id,new ScannerFolio('MOV-20260718-ABC123'),'Persona','E1','A',new DateTimeImmutable('2026-07-18 08:00'),$actor));test('movimiento completo',fn()=>same('Persona',$mv->findById($movement->id)->personaEntregaNombre));$mv->closeAsReturned($movement->id,new DateTimeImmutable('2026-07-18 10:00'),7,'Responsable',7200);test('duración persistida',fn()=>same(7200,$mv->findById($movement->id)->duracionSegundos));$ins=new PdoScannerInspectionRepository($pdo);$delivery=$ins->createInspection(new ScannerInspectionCreateData($movement->id,$scanner->id,new InspectionType('entrega'),new DateTimeImmutable(),$actor,new BatteryPercentage(95),5,'ok',details:[new ScannerInspectionDetailData('pantalla','excelente')]));$return=$ins->createInspection(new ScannerInspectionCreateData($movement->id,$scanner->id,new InspectionType('recepcion'),new DateTimeImmutable(),$actor,new BatteryPercentage(80),3,'daño',details:[new ScannerInspectionDetailData('pantalla','dañado')]));test('inspecciones scanner',fn()=>same(2,count($ins->listByScannerId($scanner->id))));test('inspecciones movimiento',fn()=>same(2,count($ins->listByMovementId($movement->id))));test('detalles',fn()=>same('pantalla',$ins->listDetailsByInspectionId($delivery->id)[0]['componente']));$ir=new PdoScannerIncidentRepository($pdo);$incident=$ir->create(new ScannerIncidentCreateData($scanner->id,'daño',new IncidentSeverity('media'),'Pantalla',new DateTimeImmutable(),$actor));$ir->changeSeverity($incident->id,new IncidentSeverity('alta'),7);test('severidad cambiada',fn()=>same('alta',(string)$ir->findById($incident->id)->severity));$ev=new PdoEvidenceRepository($pdo);$eid=$ev->create(new ScannerEvidenceMetadata($scanner->id,'foto','x.jpg','image/jpeg',10,str_repeat('a',64),new DateTimeImmutable(),$actor,$movement->id,$return->id,$incident->id));test('evidencia relaciones',function()use($ev,$movement,$return,$incident){same(1,count($ev->listByMovementId($movement->id)));same(1,count($ev->listByInspectionId($return->id)));same(1,count($ev->listByIncidentId($incident->id)));});$audit=new PdoAuditRepository($pdo);$audit->append(new AuditEventData($actor,'actualizar','control-escaneres','scanner','exito',new DateTimeImmutable(),$scanner->id,['password'=>'x'],['estado'=>'ok'],requestId:'REQ-1'));$aq=new PdoAuditQueryRepository($pdo);test('auditoría lectura',fn()=>same('REQ-1',$aq->listByEntity('scanner',$scanner->id)[0]['request_id']));$dash=new PdoScannerDashboardQuery($pdo);test('query dashboard',fn()=>same(1,$dash->countActive()));test('métrica no soportada explícita',fn()=>throws(fn()=>$dash->outOfServiceTime(new DateTimeImmutable('-1 day'),new DateTimeImmutable())));$history=new PdoScannerHistoryQuery($pdo);test('historial',fn()=>same(1,count($history->listMovements($scanner->id))));$tm=new TransactionManager($pdo);test('interfaz transacción',fn()=>ok($tm instanceof App\Repositories\ControlEscaneres\Contracts\TransactionManagerInterface));test('rollback',function()use($tm,$pdo){throws(fn()=>$tm->transactional(function()use($pdo){$pdo->exec("INSERT INTO scanners(codigo,codigo_qr,marca,modelo,estado)VALUES('SC-9999','Q','X','Y','disponible')");throw new RuntimeException();}));same(0,(int)$pdo->query("SELECT COUNT(*) FROM scanners WHERE codigo='SC-9999'")->fetchColumn());});finish('Integration Compatibility');
